import pytest

# Fixture: creates admin user for tests
@pytest.fixture
def admin_user():
    return {
        "id": 1,
        "name": "Admin",
        "email": "admin@example.com",
        "role": "admin"
    }

# Fixture: database connection with setup/teardown
@pytest.fixture
def db_connection():
    db = connect_to_database()
    yield db
    db.close()  # cleanup after test

# Test using fixtures
def test_admin_can_access_page(admin_user):
    assert admin_user["role"] == "admin"
    assert admin_user["email"] == "admin@example.com"

def test_user_creation(admin_user, db_connection):
    db_connection.create_user(admin_user)
    retrieved = db_connection.get_user(admin_user["id"])
    assert retrieved["name"] == "Admin"

// Mock: simulated API client
test('fetches user data', () => {
  // Create mock API
  const mockAPI = {
    getUser: jest.fn().mockResolvedValue({ id: 1, name: 'Alice' })
  };

  // Use mock in service
  const userService = new UserService(mockAPI);
  const user = await userService.getUser(1);

  // Verify interaction
  expect(mockAPI.getUser).toHaveBeenCalledWith(1);
  expect(mockAPI.getUser).toHaveBeenCalledTimes(1);
  expect(user.name).toBe('Alice');
});

// 1. Fixture: build test data
let fixtureUser = User(id: 1, name: "Alice", email: "alice@example.com")

// 2. Stub: control what dependency returns
struct StubAPI: APIClient {
    func getUser(id: Int) -> User {
        return fixtureUser  // always returns same data
    }
}

// 3. Mock: assert interactions
class MockAnalytics: AnalyticsTracker {
    var eventsSent: [String] = []

    func sendEvent(_ name: String) {
        eventsSent.append(name)
    }
}

// Test using all three
func testUserLogin() {
    let stubAPI = StubAPI()
    let mockAnalytics = MockAnalytics()

    let authService = AuthService(api: stubAPI, analytics: mockAnalytics)
    authService.login(userid: 1)

    // Verify fixture data was used
    XCTAssertEqual(authService.currentUser?.name, "Alice")

    // Verify mock interaction
    XCTAssertEqual(mockAnalytics.eventsSent, ["user_login"])
}
